class Solution {
public:
    int maximumCostSubstring(string s, string chars, vector<int>& vals) {
        int val[26];
        for (int i = 0; i < 26; ++i) val[i] = i + 1;
        for (int i = 0; i < chars.size(); ++i) val[chars[i] - 'a'] = vals[i];

        int maxCost = 0, cur = 0;
        for (char c : s) {
            cur += val[c - 'a'];
            if (cur < 0) cur = 0;
            if (cur > maxCost) maxCost = cur;
        }
        return maxCost;
    }
};
```
